<style>
  /* ===== WHY US – PREMIUM ===== */

  .why-card {
    opacity: 0;
    transform: translateY(40px);
    transition: opacity .7s ease, transform .7s ease;
  }

  .why-card.in-view {
    opacity: 1;
    transform: translateY(0);
  }

  .why-us-new {
    background: #fafafa;
    padding: 90px 0;
  }

  .why-header {
    text-align: center;
    max-width: 900px;
    margin: 0 auto 70px;
  }

  .why-header h2 {
    font-size: 34px;
    font-weight: 600;
    letter-spacing: 1px;
    color: #222;
  }

  .gold-line {
    display: block;
    width: 80px;
    height: 3px;
    margin: 14px auto 24px;
    background: linear-gradient(90deg, #d4af37, #f5e6c8);
  }

  .why-header p {
    font-size: 16px;
    line-height: 1.8;
    color: #555;
  }

  /* GRID */

  .why-cards .col-md-3 {
    margin-bottom: 30px;
  }

  /* CARD */

  .why-card {
    border: 1px solid transparent;

    background: #fff;
    padding: 40px 20px;
    text-align: center;
    border-radius: 14px;
    transition: all .4s ease;
    box-shadow: 0 10px 30px rgba(0, 0, 0, .04);
    height: 100%;
  }

  .why-card img {
    height: 60px;
    margin-bottom: 18px;
    transition: transform .4s ease, filter .4s ease;
    opacity: .9;
    filter: grayscale(100%) brightness(0.2);

  }

  .why-card h4 {
    font-size: 24px;
    font-weight: 700;
    letter-spacing: .5px;
    color: #222;
    margin-bottom: 6px;
  }

  .why-card span {
    font-size: 14px;
    letter-spacing: .4px;
    color: #666;
  }

  /* HOVER EFFECTS */

  .why-card:hover {
    transform: translateY(-6px);
    box-shadow: 0 20px 45px rgba(0, 0, 0, .08);
    border-color: rgba(212, 175, 55, .35);
  }

  .why-card:hover img {
    transform: scale(1.1);
    filter: drop-shadow(0 6px 10px rgba(212, 175, 55, .35));
  }

  /* MOBILE */

  @media(max-width:768px) {
    .why-header h2 {
      font-size: 28px;
    }
    .why-card h4{
        font-size:18px
    }
    .why-card span{
        line-height: 1;
    }
    .why-card{
        padding:20px 10px;
    }
    .why-us-new{
        padding:30px
    }
  }

  .why-icon {
    color: #333;
    /* default icon color */
    margin-bottom: 18px;
    transition: color .4s ease, transform .4s ease;
  }

  .why-card:hover .why-icon {
    color: #d4af37;
    /* gold */
    transition: transform .4s ease, filter .4s ease;

    transform: scale(1.1);
  }

  .why-icon svg {
    width: 60px;
    height: 60px;
  }
</style>
